 * @param {string} authToken - Short-lived JWT for API auth
 * @throws {Error} If input is invalid
 */
function validatePaymentInput(paymentToken, amountCents, authToken) {
  // Validate payment token (adjust format per your processor, e.g., Stripe)
  if (!paymentToken || typeof paymentToken !== 'string' || paymentToken.length < 12) {
    throw new Error('Invalid payment token');
  }

  // Validate amount (positive integer, no decimals, within limits)
  if (
    typeof amountCents !== 'number' ||
    !Number.isInteger(amountCents) ||
    amountCents <= 0 ||
    amountCents > MAX_CHARGE_AMOUNT_CENTS
  ) {
    throw new Error('Invalid amount: Must be a positive integer (cents for USD)');
  }

  // Validate auth token
  if (!authToken || typeof authToken !== 'string') {
    throw new Error('Missing authentication');
  }
}

